            if (!isTaskMissionStillCurrent()) {
                removeLoadingMessage();
                return stopStaleTaskFinalization('모델 응답이 도착했지만 현재 미션이 바뀌어 이전 요청의 응답 적용을 중단했습니다.');
            }
